import { RawVessel, Vessel } from "./types";

// Marine-specific images for fallback
const marineImages = [
  "https://images.unsplash.com/photo-1567899378494-47b22a2ae96a?w=800",
  "https://images.unsplash.com/photo-1500417148159-68083bd7333a?w=800",
  "https://images.unsplash.com/photo-1569263979104-865ab7cd8d13?w=800",
  "https://images.unsplash.com/photo-1605281317010-fe5ffe798166?w=800",
  "https://images.unsplash.com/photo-1544551763-46a013bb70d5?w=800",
];

export function cleanData(data: RawVessel[]): Vessel[] {
  // Remove entries with no valid name
  const cleaned = data.filter(item => item.name && item.name.trim().length > 5);

  return cleaned.map((item, index) => {
    const nameStr = item.name.trim();

    // --- ANALYZE: Extract year ---
    const yearMatch = nameStr.match(/\b(19|20)\d{2}\b/);
    const year = yearMatch ? yearMatch[0] : "Unknown";

    // --- ANALYZE: Extract vessel type ---
    const lower = nameStr.toLowerCase();
    let type = "Vessel";
    if (/yacht|motor yacht|flybridge/.test(lower)) type = "Motor Yacht";
    else if (/sail|ketch|sloop|cutter/.test(lower)) type = "Sailboat";
    else if (/cruiser|pilothouse/.test(lower)) type = "Cruiser";
    else if (/trawler|fishing|commercial|charter|dive/.test(lower)) type = "Commercial";
    else if (/sports|speed|wave|powerboat/.test(lower)) type = "Powerboat";

    // --- ANALYZE: Determine auction status ---
    const isUnreserved = lower.includes("unreserved");
    const status = isUnreserved ? "Unreserved Auction" : "Upcoming Auction";

    // --- CLEAN: Strip "Located:" from location ---
    const rawLocation = item.location || "";
    const location = rawLocation
      .replace(/Located:\s*/i, "")
      .split(/\n/)[0]
      .trim() || "Global";

    // --- CLEAN: Image - prefer scraped, fallback to marine stock ---
    const image =
      item.image && item.image.startsWith("http") && !item.image.includes("svg")
        ? item.image
        : marineImages[index % marineImages.length];

    // --- CLEAN: Price formatting ---
    const price = item.price && item.price.trim().length > 0 ? item.price : "Register to Bid";

    return {
      id: item.id,
      name: nameStr,
      price,
      location,
      image,
      status,
      source: item.source,
      description: `${nameStr} is a ${type.toLowerCase()} currently listed for auction via ${item.source}. ${location !== "Global" ? `Located in ${location}.` : ""} ${isUnreserved ? "This vessel is unreserved and must be sold." : "Place your bids online before the closing date."} Year: ${year}.`,
      year,
      type,
    };
  });
}