import Link from "next/link";
import Image from "next/image";
import { notFound } from "next/navigation";
import { Badge } from "@/components/ui/badge";
import { Vessel } from "../../lib/types";
import { scrapeVessels } from "../../lib/scraper";
import { cleanData } from "../../lib/clean";

export default async function VesselDetailsPage({
  params,
}: {
  params: { id: string };
}) {
  const raw = await scrapeVessels();
  const vessels: Vessel[] = cleanData(raw);

  // ID can be string like "au_0" or "eco_1"
  const vessel = vessels.find((v: Vessel) => String(v.id) === String(params.id));

  if (!vessel) return notFound();

  return (
    <div className="container mx-auto px-4 py-10 max-w-5xl">
      {/* Back Button */}
      <Link
        href="/auctions"
        className="inline-flex items-center gap-2 text-[#0f2846] font-semibold hover:text-[#0EA5E9] mb-8 transition"
      >
        ← Back to Auctions
      </Link>

      {/* Header */}
      <div className="flex flex-wrap gap-4 items-center mb-6">
        <h1 className="text-3xl md:text-4xl font-bold text-[#0f2846]">{vessel.name}</h1>
        <Badge className="bg-[#0EA5E9] text-white px-3 py-1">{vessel.status}</Badge>
      </div>

      {/* Main Grid */}
      <div className="grid md:grid-cols-2 gap-10">
        {/* Image */}
        <div>
          <Image
            src={vessel.image || "https://images.unsplash.com/photo-1567899378494-47b22a2ae96a?w=800"}
            alt={vessel.name || "Vessel"}
            width={800}
            height={500}
            className="w-full h-[380px] object-cover rounded-2xl shadow-lg"
            unoptimized
          />
        </div>

        {/* Details */}
        <div className="flex flex-col gap-4">
          <div className="text-3xl font-bold text-[#0EA5E9]">{vessel.price}</div>

          <div className="bg-gray-50 rounded-xl p-6 space-y-3 shadow-sm border">
            <div className="flex items-center gap-3">
              <span className="text-gray-500 w-24 font-medium">Location</span>
              <span className="font-semibold text-[#0f2846]">{vessel.location || "—"}</span>
            </div>
            <div className="flex items-center gap-3">
              <span className="text-gray-500 w-24 font-medium">Year</span>
              <span className="font-semibold text-[#0f2846]">{vessel.year || "—"}</span>
            </div>
            <div className="flex items-center gap-3">
              <span className="text-gray-500 w-24 font-medium">Type</span>
              <span className="font-semibold text-[#0f2846]">{vessel.type || "—"}</span>
            </div>
            <div className="flex items-center gap-3">
              <span className="text-gray-500 w-24 font-medium">Source</span>
              <span className="font-semibold text-[#0f2846]">{vessel.source || "—"}</span>
            </div>
          </div>

          <Link
            href="/auctions"
            className="mt-4 bg-[#0EA5E9] hover:bg-blue-600 transition text-white text-center font-bold py-3 px-6 rounded-xl shadow"
          >
            View All Auctions
          </Link>
        </div>
      </div>

      {/* Description */}
      <div className="mt-10 bg-white rounded-2xl border p-8 shadow-sm">
        <h2 className="text-2xl font-bold text-[#0f2846] mb-4">Description</h2>
        <p className="text-gray-600 leading-relaxed text-lg">{vessel.description}</p>
      </div>
    </div>
  );
}