import axios from "axios";
import * as cheerio from "cheerio";
import { RawVessel } from "./types";

export async function scrapeVessels(): Promise<RawVessel[]> {
  const results: RawVessel[] = [];

  // ---------------- SITE 1 (Maritime Eco - WooCommerce, try public API) ----------------
  try {
    const { data } = await axios.get(
      "https://maritimeauction.eco/wp-json/wc/v3/products?per_page=20&status=publish",
      { timeout: 10000 }
    );
    if (Array.isArray(data)) {
      data.forEach((item: { id: number; name: string; price: string; images?: { src: string }[] }) => {
        results.push({
          id: `eco_${item.id}`,
          name: item.name,
          price: item.price ? `€${item.price}` : "Auction",
          image: item.images?.[0]?.src || "",
          source: "Maritime Auction Eco",
        });
      });
    }
  } catch {
    // ECO API requires authentication - skip silently
  }

  // ---------------- SITE 2 (Marine Auctions AU - Cheerio HTML parse) ----------------
  try {
    const { data } = await axios.get(
      "https://www.marineauctions.com.au/forthcoming-auctions/",
      {
        timeout: 15000,
        headers: {
          "User-Agent": "Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/124.0.0.0 Safari/537.36",
          "Accept": "text/html,application/xhtml+xml,application/xml;q=0.9,image/webp,*/*;q=0.8",
          "Accept-Language": "en-US,en;q=0.9",
        },
      }
    );
    const $ = cheerio.load(data);

    // Each vessel is in a .flexItem container with: img + .flexItem__content > h4 + p(location)
    $(".flexItem").each((i, el) => {
      const name = $(el).find("h4").first().text().trim();
      if (!name || name.length < 5) return;

      // Get location from the strong tag inside the content
      const locationText = $(el).find(".flexItem__content p strong").first().text().trim();
      const location = locationText.match(/Located:\s*(.+)/)?.[1]?.split(/\n/)[0]?.trim() || "";

      // Get image - site uses data-src for lazy loading
      const imgEl = $(el).find("img").first();
      const rawImage = imgEl.attr("data-src") || imgEl.attr("src") || "";
      const image = rawImage.startsWith("http")
        ? rawImage
        : rawImage.startsWith("/")
          ? `https://www.marineauctions.com.au${rawImage}`
          : "";

      results.push({
        id: `au_${i}`,
        name,
        location,
        image,
        source: "Marine Auctions AU",
      });
    });
  } catch (err) {
    console.error("Site 2 (Marine Auctions AU) failed:", err);
  }

  return results;
}